int main() {
    EVP_PKEY *pkey = NULL;
    EVP_PKEY_CTX *pctx = NULL;
    EVP_MD_CTX *mdctx = NULL;
    unsigned char *sig = NULL;
    unsigned int sig_len = 0;
    BIGNUM *n = NULL;
    const char *msg = "Hello, OpenSSL 3.0 High-Level APIs";
    size_t msg_len = strlen(msg);

    // 1. Generate a 2048-bit RSA key
    pctx = EVP_PKEY_CTX_new_id(EVP_PKEY_RSA, NULL);
    if (!pctx) handle_errors();

    if (EVP_PKEY_ctx_set_rsa_keygen_bits(pctx, 2048) <= 0) handle_errors();

    if (EVP_PKEY_keygen_init(pctx) <= 0) handle_errors();

    if (EVP_PKEY_keygen(pctx, &pkey) <= 0) handle_errors();
    EVP_PKEY_CTX_free(pctx);

    // 2. Sign the SHA-256 digest of a message
    mdctx = EVP_MD_CTX_new();
    if (!mdctx) handle_errors();

    if (EVP_DigestSignInit(mdctx, EVP_sha256(), NULL, pkey) <= 0) handle_errors();

    if (EVP_DigestSignUpdate(mdctx, msg, msg_len) <= 0) handle_errors();

    sig =malloc(EVP_PKEY_size(pkey)); // Rough estimate for buffer
    if (EVP_DigestSignFinal(mdctx, sig, &sig_len) <= 0) handle_errors();

    printf("Signature: ");
    for (unsigned int i = 0; i < sig_len; i++) printf("%02x", sig[i]);
    printf("\n");

    // 3. Extract the modulus n as a BIGNUM
    // EVP_PKEY_get_bn_param is the high-level way to access RSA parameters
    if (EVP_PKEY_get_bn_param(pkey, EVP_PKEY_PUB_PARAM_MODULUS, &n) <= 0) {
        handle_errors();
    }

    printf("Modulus n: ");
    BN_print_f(n);
    printf("\n");

    // Cleanup
    free(sig);
    BN_free(n);
    EVP_MD_CTX_free(mdctx);
    EVP_PKEY_free(pkey);

    return 0;
}
