    EVP_MAC *mac = EVP_MAC_fetch(NULL, "HMAC", NULL);
    if (!mac) {
        fprintf(stderr, "Failed to fetch HMAC\n");
        return 1;
    }

    // 2. Create a context
    EVP_MAC_CTX *ctx = EVP_MAC_CTX_new();
    if (!ctx) {
        EVP_MAC_free(mac);
        return 1;
    }

