    OSSL_PARAM params[2];
    params[0] = OSSL_PARAM_construct_utf8_string("digests", "SHA256", 0);
    params[1] = OSSL_PARAM_construct_end();

    // 4. Init with key and digest via OSSL_PARAM
    if (EVP_MAC_init(mac, ctx, params, (unsigned char *)key, strlen(key)) <= 0) {
        fprintf(stderr, "EVP_MAC_init failed\n");
        goto cleanup;
    }

    // 5. Update
    if (EVP_MAC_update(ctx, (unsigned char *)data, strlen(data)) <= 0) {
        fprintf(stderr, "EVP_MAC_update failed\n");
        goto cleanup;
    }

    // 6. Finalize
    if (EVP_MAC_finalize(ctx, out, sizeof(out), sizeof(out)) <= 0) {
        fprintf(stderr, "EVP_MAC_finalize failed\n");
        goto cleanup;
    }

    printf("HMAC-SHA256: ");
    for (int i = 0; i < 32; i++) printf("%02x", out[i]);
    printf("\n");

